/// Generate plots for all multi-driver groups
pub(super) fn generate_plots_for_multi_drivers(
    output_json_path: &Path,
    multi_driver_groups: &[MultiDriverGroupInfo],
    output_dir: &Path,
    test_idx: usize,
    sample_rate: f64,
    verbose: bool,
) -> Result<(), Box<dyn Error>> {
    // Read the roomeq output JSON
    let output_json = fs::read_to_string(output_json_path)?;
    let roomeq_output: RoomeqOutput = serde_json::from_str(&output_json)?;

    for group in multi_driver_groups {
        let channel_output = match roomeq_output.channels.get(&group.channel_name) {
            Some(ch) => ch,
            None => {
                if verbose {
                    println!(
                        "      Warning: channel '{}' not found in output",
                        group.channel_name
                    );
                }
                continue;
            }
        };

        let drivers_output = match &channel_output.drivers {
            Some(d) => d,
            None => {
                if verbose {
                    println!(
                        "      Warning: channel '{}' has no driver output",
                        group.channel_name
                    );
                }
                continue;
            }
        };

        // Extract crossover gains and frequencies from plugins
        let mut gains = Vec::new();
        let mut crossover_freqs = Vec::new();

        for driver in drivers_output {
            for plugin in &driver.plugins {
                if plugin.plugin_type == "Gain" {
                    if let Some(gain) = plugin.parameters.get("gain_db").and_then(|v| v.as_f64()) {
                        gains.push(gain);
                    }
                } else if plugin.plugin_type == "Biquad"
                    && let Some(freq) = plugin.parameters.get("freq").and_then(|v| v.as_f64())
                {
                    crossover_freqs.push(freq);
                }
            }
        }

        // We expect N gains and N-1 crossover frequencies (duplicates removed)
        crossover_freqs.sort_by(|a, b| a.total_cmp(b));
        crossover_freqs.dedup_by(|a, b| (*a - *b).abs() < 1.0);

        if crossover_freqs.len() != group.measurement_sources.len() - 1 {
            if verbose {
                println!(
                    "      Warning: expected {} xover freqs but found {}",
                    group.measurement_sources.len() - 1,
                    crossover_freqs.len()
                );
                println!("      Frequencies: {:?}", crossover_freqs);
                println!("      Skipping plot generation for this group");
            }
            continue;
        }

        // Load measurements
        let mut driver_measurements = Vec::new();
        for lib_source in &group.measurement_sources {
            // Load and average
            let curve = autoeq::load_source(lib_source)?;

            driver_measurements.push(autoeq::loss::DriverMeasurement {
                freq: curve.freq,
                spl: curve.spl,
                phase: curve.phase,
            });
        }

        // Parse crossover type
        let crossover_type: autoeq::loss::CrossoverType =
            group.crossover_type.parse().unwrap_or_default();

        // Create DriversLossData
        let drivers_data = autoeq::loss::DriversLossData::new(driver_measurements, crossover_type);

        // Generate plot
        let plot_path = output_dir.join(format!(
            "test_{}_{}_drivers.html",
            test_idx, group.channel_name
        ));

        autoeq::plot::plot_drivers_results(
            &drivers_data,
            &gains,
            &crossover_freqs,
            None,
            sample_rate,
            &plot_path,
        )?;

        if verbose {
            println!("      Plot saved to {:?}", plot_path);
        }
    }

    Ok(())
}

/// Generate a random RoomConfig
#[allow(clippy::type_complexity)]
pub(super) fn generate_random_config(
    output_dir: &Path,
    test_idx: usize,
    rng: &mut ChaCha8Rng,
    max_speakers: usize,
    scenario_kind: ScenarioKind,
) -> Result<(RoomConfig, Vec<PathBuf>, Vec<MultiDriverGroupInfo>), Box<dyn Error>> {
    if scenario_kind == ScenarioKind::RandomMixed {
        return generate_random_mixed_config(output_dir, test_idx, rng, max_speakers);
    }

    generate_stratified_config(output_dir, test_idx, rng, scenario_kind)
}

#[allow(clippy::type_complexity)]
pub(super) fn generate_stratified_config(
    output_dir: &Path,
    test_idx: usize,
    rng: &mut ChaCha8Rng,
    scenario_kind: ScenarioKind,
) -> Result<(RoomConfig, Vec<PathBuf>, Vec<MultiDriverGroupInfo>), Box<dyn Error>> {
    let mut speakers = HashMap::new();
    let mut measurement_files = Vec::new();
    let mut multi_driver_groups = Vec::new();
    let mut crossovers = HashMap::new();

    match scenario_kind {
        ScenarioKind::Group2Way | ScenarioKind::Group3Way => {
            let channel_name = "L".to_string();
            let num_drivers = if scenario_kind == ScenarioKind::Group2Way {
                2
            } else {
                3
            };
            let mut driver_sources = Vec::new();
            for d in 0..num_drivers {
                let (source, paths) = generate_random_source(
                    rng,
                    output_dir,
                    test_idx,
                    &channel_name,
                    "driver",
                    d,
                    num_drivers,
                    None,
                )?;
                measurement_files.extend(paths);
                driver_sources.push(source);
            }

            let xover_id = format!("xover_{}", channel_name);
            let xover_type = if num_drivers == 2 { "LR24" } else { "LR12" }.to_string();
            crossovers.insert(
                xover_id.clone(),
                CrossoverConfig {
                    crossover_type: xover_type.clone(),
                    frequency: None,
                    frequencies: None,
                    frequency_range: Some((200.0, 5000.0)),
                },
            );

            multi_driver_groups.push(MultiDriverGroupInfo {
                channel_name: channel_name.clone(),
                measurement_sources: driver_sources.clone(),
                crossover_type: xover_type,
            });

            speakers.insert(
                channel_name.clone(),
                SpeakerConfig::Group(SpeakerGroup {
                    name: channel_name,
                    speaker_name: Some(random_speaker_name(rng)),
                    measurements: driver_sources,
                    crossover: Some(xover_id),
                }),
            );
        }
        ScenarioKind::MultiSub
        | ScenarioKind::MultiSubAllpass
        | ScenarioKind::MultiSubMultiSeat => {
            let num_subs = if scenario_kind == ScenarioKind::MultiSub {
                2
            } else {
                3
            };
            let forced_measurements = if scenario_kind == ScenarioKind::MultiSubMultiSeat {
                Some(3)
            } else {
                None
            };
            let mut sub_sources = Vec::new();
            for d in 0..num_subs {
                let (source, paths) = generate_random_source(
                    rng,
                    output_dir,
                    test_idx,
                    "LFE",
                    "sub",
                    d,
                    num_subs,
                    forced_measurements,
                )?;
                measurement_files.extend(paths);
                sub_sources.push(source);
            }

            speakers.insert(
                "LFE".to_string(),
                SpeakerConfig::MultiSub(MultiSubGroup {
                    name: "MultiSub".to_string(),
                    speaker_name: Some(random_speaker_name(rng)),
                    subwoofers: sub_sources,
                    allpass_optimization: scenario_kind == ScenarioKind::MultiSubAllpass,
                }),
            );
        }
        ScenarioKind::Dba => {
            let (source_f, paths_f) =
                generate_random_source(rng, output_dir, test_idx, "LFE", "front", 0, 1, None)?;
            let (source_r, paths_r) =
                generate_random_source(rng, output_dir, test_idx, "LFE", "rear", 0, 1, None)?;
            measurement_files.extend(paths_f);
            measurement_files.extend(paths_r);

            speakers.insert(
                "LFE".to_string(),
                SpeakerConfig::Dba(DBAConfig {
                    name: "DBA".to_string(),
                    speaker_name: Some(random_speaker_name(rng)),
                    front: vec![source_f],
                    rear: vec![source_r],
                }),
            );
        }
        ScenarioKind::Cardioid => {
            let (front, paths_f) =
                generate_random_source(rng, output_dir, test_idx, "LFE", "front", 0, 2, None)?;
            let (rear, paths_r) =
                generate_random_source(rng, output_dir, test_idx, "LFE", "rear", 1, 2, None)?;
            measurement_files.extend(paths_f);
            measurement_files.extend(paths_r);

            speakers.insert(
                "LFE".to_string(),
                SpeakerConfig::Cardioid(Box::new(CardioidConfig {
                    name: "Cardioid".to_string(),
                    speaker_name: Some(random_speaker_name(rng)),
                    front,
                    rear,
                    separation_meters: rng.random_range(0.25..1.20),
                })),
            );
        }
        ScenarioKind::ChannelMatching => {
            for channel in ["L", "R"] {
                let (source, paths) =
                    generate_random_source(rng, output_dir, test_idx, channel, "main", 0, 1, None)?;
                measurement_files.extend(paths);
                speakers.insert(channel.to_string(), SpeakerConfig::Single(source));
            }
        }
        ScenarioKind::GroupDelay => {
            for (idx, channel) in ["L", "R", "C"].iter().enumerate() {
                let (source, paths) = generate_random_source(
                    rng, output_dir, test_idx, channel, "main", idx, 1, None,
                )?;
                measurement_files.extend(paths);
                speakers.insert((*channel).to_string(), SpeakerConfig::Single(source));
            }
        }
        ScenarioKind::SupportingSource => {
            for (idx, channel) in ["L", "R"].iter().enumerate() {
                let (source, paths) = generate_random_source(
                    rng, output_dir, test_idx, channel, "main", idx, 1, None,
                )?;
                measurement_files.extend(paths);
                speakers.insert((*channel).to_string(), SpeakerConfig::Single(source));
            }
            let (primary, paths_p) = generate_random_source(
                rng, output_dir, test_idx, "WideLeft", "primary", 0, 1, None,
            )?;
            measurement_files.extend(paths_p);
            let (support, paths_s) = generate_random_source(
                rng, output_dir, test_idx, "WideLeft", "support", 0, 1, None,
            )?;
            measurement_files.extend(paths_s);
            speakers.insert(
                "WideLeft".to_string(),
                SpeakerConfig::SupportingSource(SupportingSourceGroup {
                    name: "WideLeft".to_string(),
                    speaker_name: None,
                    primary,
                    support,
                    supporting_source: SupportingSourceConfig {
                        fir_taps: 256,
                        decorrelation: SupportingSourceDecorrelation::None,
                        ..Default::default()
                    },
                }),
            );
        }
        ScenarioKind::MultiMeasurementAverage
        | ScenarioKind::MultiMeasurementWeightedSum
        | ScenarioKind::MultiMeasurementMinimax
        | ScenarioKind::MultiMeasurementVariancePenalized
        | ScenarioKind::MultiMeasurementSpatialRobustness => {
            let (source, paths) =
                generate_random_source(rng, output_dir, test_idx, "L", "main", 0, 1, Some(3))?;
            measurement_files.extend(paths);
            speakers.insert("L".to_string(), SpeakerConfig::Single(source));
        }
        ScenarioKind::SingleLowLatency
        | ScenarioKind::SinglePhaseLinear
        | ScenarioKind::SingleHybrid
        | ScenarioKind::SingleMixedPhase
        | ScenarioKind::SingleWarpedIir
        | ScenarioKind::SingleKautzModal
        | ScenarioKind::RandomMixed => {
            let (source, paths) =
                generate_random_source(rng, output_dir, test_idx, "L", "main", 0, 1, None)?;
            measurement_files.extend(paths);
            speakers.insert("L".to_string(), SpeakerConfig::Single(source));
        }
    }

    let processing_mode = scenario_kind.processing_mode(rng);
    let mut optimizer = base_optimizer_config(processing_mode, rng);

    if let Some(strategy) = scenario_kind.multi_measurement_strategy() {
        optimizer.multi_measurement = Some(multi_measurement_config(strategy, 3));
    }

    if scenario_kind == ScenarioKind::MultiSubMultiSeat {
        optimizer.multi_seat = Some(MultiSeatConfig {
            enabled: true,
            strategy: MultiSeatStrategy::MinimizeVariance,
            optimize_polarity: true,
            allpass_filters_per_sub: 1,
            ..Default::default()
        });
    }

    if scenario_kind == ScenarioKind::ChannelMatching {
        optimizer.channel_matching = Some(ChannelMatchingConfig {
            enabled: true,
            threshold_db: 0.1,
            max_filters: 3,
        });
    }

    if scenario_kind == ScenarioKind::GroupDelay {
        optimizer.group_delay = Some(GroupDelayOptimizationConfig {
            enabled: true,
            max_iter: 80,
            popsize: 8,
            ap_per_channel: 0,
            min_improvement_db: 0.0,
            adaptive_allpass: false,
            ..Default::default()
        });
    }

    let target_curve = if rng.random_bool(0.3) {
        Some(TargetCurveConfig::Predefined("harman".to_string()))
    } else {
        None
    };

    let mut room_config = RoomConfig {
        version: autoeq::roomeq::default_config_version(),
        system: None,
        speakers,
        crossovers: if crossovers.is_empty() {
            None
        } else {
            Some(crossovers)
        },
        target_curve,
        optimizer,
        recording_config: None,
        ctc: None,
        cea2034_cache: None,
    };

    if scenario_kind == ScenarioKind::SupportingSource {
        room_config.system = Some(SystemConfig {
            model: SystemModel::HomeCinema,
            speakers: HashMap::from([
                ("Left".to_string(), "L".to_string()),
                ("Right".to_string(), "R".to_string()),
                ("WideLeft".to_string(), "WideLeft".to_string()),
            ]),
            subwoofers: None,
            bass_management: None,
            ..Default::default()
        });
    }

    Ok((room_config, measurement_files, multi_driver_groups))
}

#[allow(clippy::type_complexity)]
pub(super) fn generate_random_mixed_config(
    output_dir: &Path,
    test_idx: usize,
    rng: &mut ChaCha8Rng,
    max_speakers: usize,
) -> Result<(RoomConfig, Vec<PathBuf>, Vec<MultiDriverGroupInfo>), Box<dyn Error>> {
    let mut speakers = HashMap::new();
    let mut measurement_files = Vec::new();
    let mut multi_driver_groups = Vec::new();
    let mut crossovers = HashMap::new();

    let num_speakers = rng.random_range(1..=max_speakers);
    let channels = ["L", "R", "C", "SL", "SR", "SBL", "SBR"];

    for i in 0..num_speakers {
        let channel_name = channels[i % channels.len()].to_string();

        // Randomly choose speaker type
        let speaker_type_roll = rng.random_range(0..100);

        if speaker_type_roll < 60 {
            // 60% chance: Single speaker
            let (source, paths) = generate_random_source(
                rng,
                output_dir,
                test_idx,
                &channel_name,
                "main",
                0,
                1,
                None,
            )?;
            measurement_files.extend(paths);
            speakers.insert(channel_name, SpeakerConfig::Single(source));
        } else if speaker_type_roll < 85 {
            // 25% chance: Multi-driver group
            let num_drivers = rng.random_range(2..=3);
            let mut driver_sources = Vec::new();
            for d in 0..num_drivers {
                let (source, paths) = generate_random_source(
                    rng,
                    output_dir,
                    test_idx,
                    &channel_name,
                    "driver",
                    d,
                    num_drivers,
                    None,
                )?;
                measurement_files.extend(paths);
                driver_sources.push(source);
            }

            let xover_id = format!("xover_{}", channel_name);
            let xover_type = ["LR24", "LR12", "Butterworth12"]
                .choose(rng)
                .unwrap()
                .to_string();

            crossovers.insert(
                xover_id.clone(),
                CrossoverConfig {
                    crossover_type: xover_type.clone(),
                    frequency: None,
                    frequencies: None,
                    frequency_range: Some((200.0, 5000.0)),
                },
            );

            multi_driver_groups.push(MultiDriverGroupInfo {
                channel_name: channel_name.clone(),
                measurement_sources: driver_sources.clone(),
                crossover_type: xover_type,
            });

            speakers.insert(
                channel_name.clone(),
                SpeakerConfig::Group(SpeakerGroup {
                    name: channel_name,
                    speaker_name: Some(random_speaker_name(rng)),
                    measurements: driver_sources,
                    crossover: Some(xover_id),
                }),
            );
        } else {
            // 15% chance: Multi-sub or DBA
            let is_dba = rng.random_bool(0.5);

            if is_dba {
                let mut front_sources = Vec::new();
                let mut rear_sources = Vec::new();

                let (source_f, paths_f) =
                    generate_random_source(rng, output_dir, test_idx, "LFE", "front", 0, 1, None)?;
                measurement_files.extend(paths_f);
                front_sources.push(source_f);

                let (source_r, paths_r) =
                    generate_random_source(rng, output_dir, test_idx, "LFE", "rear", 0, 1, None)?;
                measurement_files.extend(paths_r);
                rear_sources.push(source_r);

                speakers.insert(
                    "LFE".to_string(),
                    SpeakerConfig::Dba(DBAConfig {
                        name: "DBA".to_string(),
                        speaker_name: Some(random_speaker_name(rng)),
                        front: front_sources,
                        rear: rear_sources,
                    }),
                );
            } else {
                let num_subs = rng.random_range(2..=4);
                let mut sub_sources = Vec::new();
                for d in 0..num_subs {
                    let (source, paths) = generate_random_source(
                        rng, output_dir, test_idx, "LFE", "sub", d, num_subs, None,
                    )?;
                    measurement_files.extend(paths);
                    sub_sources.push(source);
                }

                speakers.insert(
                    "LFE".to_string(),
                    SpeakerConfig::MultiSub(MultiSubGroup {
                        name: "MultiSub".to_string(),
                        speaker_name: Some(random_speaker_name(rng)),
                        subwoofers: sub_sources,
                        allpass_optimization: false,
                    }),
                );
            }
        }
    }

    // Optional target curve
    let target_curve = if rng.random_bool(0.3) {
        Some(TargetCurveConfig::Predefined("harman".to_string()))
    } else {
        None
    };

    let loss_type = "flat".to_string();
    let peq_model = if rng.random_bool(0.5) {
        "pk".to_string()
    } else {
        "ls-pk-hs".to_string()
    };
    let processing_mode = if rng.random_bool(0.7) {
        ProcessingMode::LowLatency
    } else {
        ProcessingMode::PhaseLinear
    };

    let fir_config = if matches!(processing_mode, ProcessingMode::PhaseLinear) {
        Some(autoeq::roomeq::FirConfig {
            taps: 1024,
            phase: "linear".to_string(),
            correct_excess_phase: false,
            phase_smoothing: 0.167,
            pre_ringing: None,
        })
    } else {
        None
    };

    let room_config = RoomConfig {
        version: autoeq::roomeq::default_config_version(),
        system: None,
        speakers,
        crossovers: if crossovers.is_empty() {
            None
        } else {
            Some(crossovers)
        },
        target_curve,
        optimizer: OptimizerConfig {
            algorithm: "autoeq:de".to_string(),
            num_filters: 7,
            max_iter: 100, // Small for fuzzer
            min_freq: 20.0,
            max_freq: 20000.0,
            min_q: 0.5,
            max_q: 10.0,
            min_db: -12.0,
            max_db: 12.0,
            loss_type,
            peq_model,
            processing_mode,
            fir: fir_config,
            seed: Some(rng.random()),
            ..OptimizerConfig::default()
        },
        recording_config: None,
        ctc: None,
        cea2034_cache: None,
    };

    Ok((room_config, measurement_files, multi_driver_groups))
}

/// Helper to generate random source (single file or multiple files)
#[allow(clippy::too_many_arguments)]
pub(super) fn generate_random_source(
    rng: &mut ChaCha8Rng,
    output_dir: &Path,
    test_idx: usize,
    channel: &str,
    role: &str,
    idx: usize,
    count: usize,
    forced_measurements: Option<usize>,
) -> Result<(autoeq::MeasurementSource, Vec<PathBuf>), Box<dyn Error>> {
    let mut paths = Vec::new();
    let num_files = forced_measurements.unwrap_or_else(|| {
        if rng.random_bool(0.1) {
            rng.random_range(2..=3)
        } else {
            1
        }
    });
    let is_multiple = num_files > 1;

    let mut file_strings = Vec::new();

    for i in 0..num_files {
        let speaker_config = generate_random_speaker(rng);
        let filename = if is_multiple {
            format!(
                "test_{}_{}_{}_{}_pos{}.csv",
                test_idx, channel, role, idx, i
            )
        } else {
            format!("test_{}_{}_{}_{}.csv", test_idx, channel, role, idx)
        };
        let path = output_dir.join(filename);
        generate_measurement_csv(rng, &path, &speaker_config, idx, count)?;
        let config_path = path.canonicalize()?;

        file_strings.push(config_path.to_string_lossy().to_string());
        paths.push(path);
    }

    if is_multiple {
        Ok((
            autoeq::MeasurementSource::Multiple(autoeq::read::MeasurementMultiple {
                measurements: file_strings
                    .into_iter()
                    .map(|s| autoeq::MeasurementRef::Path(PathBuf::from(s)))
                    .collect(),
                speaker_name: Some(random_speaker_name(rng)),
            }),
            paths,
        ))
    } else {
        Ok((
            autoeq::MeasurementSource::Single(autoeq::read::MeasurementSingle {
                measurement: autoeq::MeasurementRef::Path(PathBuf::from(file_strings[0].clone())),
                speaker_name: Some(random_speaker_name(rng)),
            }),
            paths,
        ))
    }
}

/// Generate random speaker configuration
pub(super) fn generate_random_speaker(rng: &mut ChaCha8Rng) -> SyntheticSpeaker {
    let filter_type = match rng.random_range(0..4) {
        0 => FilterType::Flat,
        1 => FilterType::Lowpass(rng.random_range(2000.0..15000.0)),
        2 => FilterType::Highpass(rng.random_range(50.0..500.0)),
        _ => {
            let low = rng.random_range(100.0..1000.0);
            let high = rng.random_range(low + 500.0..15000.0);
            FilterType::Bandpass(low, high)
        }
    };

    SyntheticSpeaker {
        filter_type,
        noise_level_db: rng.random_range(0.5..3.0),
        spl_offset_db: rng.random_range(-10.0..10.0),
    }
}

/// Generate synthetic measurement CSV file with realistic driver characteristics
///
/// For multi-driver systems, generates bandpass responses appropriate for each driver type:
/// - Woofer: 50-1000 Hz
/// - Midrange: 400-5000 Hz
/// - Tweeter: 2000-20000 Hz
pub(super) fn generate_measurement_csv(
    rng: &mut ChaCha8Rng,
    path: &Path,
    config: &SyntheticSpeaker,
    driver_idx: usize,
    num_drivers: usize,
) -> Result<(), Box<dyn Error>> {
    // Generate frequency points (logarithmic spacing)
    let num_points = 200;
    let min_freq: f64 = 20.0;
    let max_freq: f64 = 20000.0;
    let log_min = min_freq.ln();
    let log_max = max_freq.ln();

    let mut csv_content = String::from("freq,spl,phase\n");

    // Get driver type for multi-driver systems
    let driver_type = if num_drivers > 1 {
        Some(DriverType::for_index(driver_idx, num_drivers))
    } else {
        None
    };

    // Generate delay for phase simulation (0-5 ms)
    let delay_ms = rng.random_range(0.0..5.0);
    let mode_count = if matches!(driver_type, Some(DriverType::Tweeter)) {
        1
    } else {
        rng.random_range(2..=5)
    };
    let room_modes: Vec<(f64, f64, f64)> = (0..mode_count)
        .map(|_| {
            (
                rng.random_range(30.0..450.0),
                rng.random_range(-10.0..8.0),
                rng.random_range(0.025..0.10),
            )
        })
        .collect();

    for i in 0..num_points {
        let t = i as f64 / (num_points - 1) as f64;
        let log_freq = log_min + t * (log_max - log_min);
        let freq = log_freq.exp();

        // Start with flat response at 85 dB with small offset (limited to ±4 dB)
        let spl_offset = config.spl_offset_db.clamp(-4.0, 4.0);
        let mut spl = 85.0 + spl_offset;

        // For multi-driver systems, apply realistic bandpass characteristics
        if let Some(dt) = driver_type {
            let (low_cutoff, high_cutoff) = dt.freq_range();

            // Apply highpass rolloff (24 dB/octave below low_cutoff)
            if freq < low_cutoff {
                let octaves = (low_cutoff / freq).log2();
                spl -= 24.0 * octaves;
            }

            // Apply lowpass rolloff (24 dB/octave above high_cutoff)
            if freq > high_cutoff {
                let octaves = (freq / high_cutoff).log2();
                spl -= 24.0 * octaves;
            }
        } else {
            // Apply generic filter characteristic for single drivers
            match config.filter_type {
                FilterType::Flat => {}
                FilterType::Lowpass(f) => {
                    if freq > f {
                        spl -= 24.0 * (freq / f).log2();
                    }
                }
                FilterType::Highpass(f) => {
                    if freq < f {
                        spl -= 24.0 * (f / freq).log2();
                    }
                }
                FilterType::Bandpass(low, high) => {
                    if freq < low {
                        spl -= 24.0 * (low / freq).log2();
                    } else if freq > high {
                        spl -= 24.0 * (freq / high).log2();
                    }
                }
            }
        }

        for (mode_freq, mode_gain_db, width) in &room_modes {
            let distance = (freq / mode_freq).ln();
            spl += mode_gain_db * (-0.5 * (distance / width).powi(2)).exp();
        }

        // Add some noise
        let noise = rng.random_range(-config.noise_level_db..config.noise_level_db);
        spl += noise;

        // Simulate phase: linear phase from delay + some random variation
        let omega = 2.0 * std::f64::consts::PI * freq;
        let phase_delay = -omega * delay_ms / 1000.0;
        let phase_rand = rng.random_range(-0.1..0.1);
        let phase = (phase_delay + phase_rand).to_degrees();

        // Wrap phase to [-180, 180]
        let phase_wrapped = ((phase + 180.0) % 360.0) - 180.0;

        csv_content.push_str(&format!("{:.2},{:.2},{:.2}\n", freq, spl, phase_wrapped));
    }

    fs::write(path, csv_content)?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use rand::SeedableRng;

    #[test]
    fn generate_random_source_creates_single_measurement() {
        let temp_dir = std::env::temp_dir();
        let mut rng = ChaCha8Rng::seed_from_u64(42);
        let (source, paths) =
            generate_random_source(&mut rng, &temp_dir, 9999, "L", "main", 0, 1, None).unwrap();

        assert_eq!(paths.len(), 1);
        assert!(paths[0].exists(), "generated CSV should exist on disk");

        match source {
            autoeq::MeasurementSource::Single(single) => {
                assert!(single.speaker_name.is_some());
            }
            _ => panic!("expected Single measurement source, got {:?}", source),
        }

        // Cleanup
        let _ = std::fs::remove_file(&paths[0]);
    }

    #[test]
    fn generate_random_source_forced_measurements_creates_multiple() {
        let temp_dir = std::env::temp_dir();
        let mut rng = ChaCha8Rng::seed_from_u64(43);
        let (source, paths) =
            generate_random_source(&mut rng, &temp_dir, 9998, "LFE", "sub", 0, 1, Some(3)).unwrap();

        assert_eq!(paths.len(), 3);
        for p in &paths {
            assert!(p.exists(), "generated CSV should exist on disk");
        }

        match source {
            autoeq::MeasurementSource::Multiple(multiple) => {
                assert_eq!(multiple.measurements.len(), 3);
                assert!(multiple.speaker_name.is_some());
            }
            _ => panic!("expected Multiple measurement source, got {:?}", source),
        }

        // Cleanup
        for p in &paths {
            let _ = std::fs::remove_file(p);
        }
    }

    #[test]
    fn generate_random_source_deterministic_with_same_seed() {
        let temp_dir = std::env::temp_dir();
        let mut rng1 = ChaCha8Rng::seed_from_u64(123);
        let (_source1, paths1) =
            generate_random_source(&mut rng1, &temp_dir, 9997, "L", "main", 0, 1, None).unwrap();

        let mut rng2 = ChaCha8Rng::seed_from_u64(123);
        let (_source2, paths2) =
            generate_random_source(&mut rng2, &temp_dir, 9997, "L", "main", 0, 1, None).unwrap();

        // Same seed should produce files with identical content
        let content1 = std::fs::read_to_string(&paths1[0]).unwrap();
        let content2 = std::fs::read_to_string(&paths2[0]).unwrap();
        assert_eq!(content1, content2);

        // Cleanup
        let _ = std::fs::remove_file(&paths1[0]);
        let _ = std::fs::remove_file(&paths2[0]);
    }

    #[test]
    fn generate_random_source_csv_has_header() {
        let temp_dir = std::env::temp_dir();
        let mut rng = ChaCha8Rng::seed_from_u64(44);
        let (_source, paths) =
            generate_random_source(&mut rng, &temp_dir, 9996, "L", "main", 0, 1, None).unwrap();

        let content = std::fs::read_to_string(&paths[0]).unwrap();
        assert!(content.starts_with("freq,spl,phase\n"));

        // Cleanup
        let _ = std::fs::remove_file(&paths[0]);
    }
}
